module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    wire [size-1:0] a_ext = {mul_a};
    wire [size-1:0] b_ext = {mul_b};

    reg [2*size-1:0] r_sum_tmp1;
    reg [2*size-1:0] r_sum_tmp2;
    reg [2*size-1:0] r_mul_out;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            r_sum_tmp1 <= 0;
            r_sum_tmp2 <= 0;
            r_mul_out <= 0;
        end else begin
            r_sum_tmp1 <= (b_ext[0] ? a_ext : 0) + (b_ext[1] ? a_ext << 1 : 0);
            r_sum_tmp2 <= (b_ext[2] ? a_ext << 2 : 0) + (b_ext[3] ? a_ext << 3 : 0);
            r_mul_out <= r_sum_tmp1 + r_sum_tmp2;
        end
    end

    assign mul_out = r_mul_out;

endmodule
